import type { ScoreResult } from '../types';
import { invokeJudge } from './llmJudge';

export async function scoreFieldLevelMapping(input: string, output: string): Promise<ScoreResult> {
  const prompt = `You are an expert Contentful Data Architect evaluating an ETL pipeline.
Evaluate whether an AI agent mapped specific document elements to their exact, semantically matching fields.

### INPUT PROVIDED TO THE AGENT (Markdown + Schema Definitions):
${input}

### ACTUAL OUTPUT GENERATED BY THE AGENT (Contentful JSON):
${output}

### EVALUATION CRITERION:
**Field-Level Mapping:** Did the agent map specific paragraphs, lists, and headers to their exact, semantically matching fields within the chosen Content Type(s)?

Return ONLY valid JSON in this exact format (no markdown fences, no extra text):
{"score": <number 0.0–1.0>, "reason": "<1–2 sentences, noting any wrong fields or misaligned content>"}`;

  try {
    const { score, reason } = await invokeJudge(prompt);
    return { scorerId: 'field-level-mapping', score, reason };
  } catch (err) {
    return { scorerId: 'field-level-mapping', score: -1, reason: `Judge error: ${String(err)}` };
  }
}
